// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MyNFTMintingContract is ERC721, Ownable, ReentrancyGuard {
    enum State { MintDisabled, MintEnabled, GameSetup, GameParticipation }
    State public currentState;

    uint256 public mintCost;
    uint256 public maxSupply;
    uint256 public currentSupply;
    mapping(uint256 => uint256) public tokenReputation;

    event NFTMinted(address indexed to, uint256 tokenId);
    event GameStarted(uint256 startTime);
    event TokensClaimed(address indexed to, uint256 amount);
    event StateChanged(State newState);

    constructor(string memory name, string memory symbol, uint256 _maxSupply) ERC721(name, symbol) {
        maxSupply = _maxSupply;
        currentState = State.MintDisabled;
    }

    modifier inState(State requiredState) {
        require(currentState == requiredState, "Invalid state");
        _;
    }

    function startGame() external onlyOwner inState(State.GameSetup) {
        currentState = State.GameParticipation;
        emit GameStarted(block.timestamp);
        emit StateChanged(currentState);
    }

    function allowPublicMinting(bool enabled) external onlyOwner {
        if (enabled) {
            currentState = State.MintEnabled;
        } else {
            currentState = State.MintDisabled;
        }
        emit StateChanged(currentState);
    }

    function mintNFT() external payable nonReentrant {
        require(currentState == State.MintEnabled, "Minting not allowed");
        require(msg.value >= mintCost, "Insufficient funds");
        require(currentSupply < maxSupply, "Max supply reached");

        uint256 newTokenId = totalSupply();
        _mint(msg.sender, newTokenId);
        currentSupply++;
        emit NFTMinted(msg.sender, newTokenId);
    }

    function setReputation(uint256 tokenId, uint256 reputation) external onlyOwner {
        require(_exists(tokenId), "Token does not exist");
        tokenReputation[tokenId] = reputation;
    }

    function claimRewards() external nonReentrant {
        require(currentState == State.GameParticipation, "Not in game participation state");

        uint256 totalReputation = 0;
        for (uint256 i = 0; i < balanceOf(msg.sender); i++) {
            uint256 tokenId = tokenOfOwnerByIndex(msg.sender, i);
            require(tokenReputation[tokenId] > 0, "No reputation to claim");
            totalReputation += tokenReputation[tokenId];
            tokenReputation[tokenId] = 0;
        }

        // Logic to calculate and send rewards based on totalReputation
        // For simplicity, assume 1 reward token per reputation point
        bool success = payable(msg.sender).call{value: totalReputation}("");
        require(success, "Transfer failed");
        emit TokensClaimed(msg.sender, totalReputation);
    }

    function withdrawFunds() external nonReentrant onlyOwner {
        uint256 balance = address(this).balance;
        bool success = payable(owner()).send(balance);
        require(success, "Transfer failed");
    }

    function resetParticipantCounts() external onlyOwner {
        // Reset state to GameSetup and clear participant counts
        currentState = State.GameSetup;
        currentSupply = 0;
        emit StateChanged(currentState);
    }

    function setState(State newState) external onlyOwner {
        require(uint8(newState) < 4, "Invalid state");
        require(
            (currentState == State.MintDisabled && newState == State.MintEnabled) ||
            (currentState == State.MintEnabled && newState == State.GameSetup) ||
            (currentState == State.GameSetup && newState == State.GameParticipation) ||
            (currentState == State.GameParticipation && newState == State.MintDisabled),
            "Invalid transition"
        );
        currentState = newState;
        emit StateChanged(newState);
    }
}
